/**
 * VideoHub360 Admin JavaScript
 *
 * Handles admin panel functionality including shortcodes page copy-to-clipboard
 */

(function($) {
    'use strict';

    /**
     * Initialize shortcodes page functionality
     */
    function initShortcodesPage() {
        // Copy to clipboard functionality
        $('.vh360-copy-btn').on('click', function(e) {
            e.preventDefault();
            var button = $(this);
            var shortcode = button.data('shortcode');

            // Function to show visual feedback
            function showSuccess() {
                var originalHtml = button.html();
                button.html('<span class="dashicons dashicons-yes"></span> ' + vh360Admin.copiedText);
                button.addClass('vh360-copied');

                setTimeout(function() {
                    button.html(originalHtml);
                    button.removeClass('vh360-copied');
                }, 2000);
            }

            // Try modern Clipboard API first
            if (navigator.clipboard && navigator.clipboard.writeText) {
                navigator.clipboard.writeText(shortcode).then(function() {
                    showSuccess();
                }).catch(function(err) {
                    console.error('Clipboard API failed, trying fallback:', err);
                    // Fallback to execCommand
                    copyFallback();
                });
            } else {
                // Fallback for older browsers
                copyFallback();
            }

            // Fallback copy method using execCommand
            function copyFallback() {
                var tempTextarea = $('<textarea>');
                tempTextarea.val(shortcode);
                tempTextarea.css({
                    position: 'absolute',
                    left: '-9999px'
                });
                $('body').append(tempTextarea);
                tempTextarea.select();

                try {
                    var successful = document.execCommand('copy');
                    if (successful) {
                        showSuccess();
                    } else {
                        console.error('Copy command was unsuccessful');
                    }
                } catch(err) {
                    console.error('Failed to copy:', err);
                }

                tempTextarea.remove();
            }
        });
    }

    // Initialize when document is ready
    $(document).ready(function() {
        // Only initialize on shortcodes page
        if ($('.vh360-shortcodes-page').length) {
            initShortcodesPage();
        }
    });

})(jQuery);
